        if folder != "sent":
            continue
        from_addr = (email.get("from_addr") or email.get("from") or "").lower().strip()
        to_addr_raw = (email.get("to_addr") or email.get("to") or "").strip()
        subject = (email.get("subject") or "").strip()
        # Normalize from address
        if from_addr != "a.costa@mojavecrest.com":
