from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox.json"}
    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found"}
    with open(mailbox_path, "r") as f:
        data = json.load(f)
    emails = data.get("emails", [])

    # Find the target sent email to asolis@griffinmedical.org
    target_email = None
    for email in emails:
        if email.get("folder", "").lower() != "sent":
            continue
        to_addr = (email.get("to_addr") or email.get("to") or "").lower().strip()
        # Normalize unicode characters that may appear
        to_normalized = to_addr.replace("\u02c6", "i").replace("\ufb01", "fi")
        if "asolis@griffinmedical.org" in to_normalized or "asolis@grif" in to_normalized:
            target_email = email
            break

    if target_email is None:
        return {"pass": False, "score": 0.0, "feedback": "Could not find a sent email to asolis@griffinmedical.org in mailbox.json. Sent emails found: " + str([(e.get('to_addr') or e.get('to','')) for e in emails if e.get('folder','').lower() == 'sent'])}

    body = (target_email.get("body_text") or "").strip()
    if not body:
        body = (target_email.get("body") or "").strip()

    # Check for attachments - the rubric says body must have boilerplate OR attach the letter as a file
    attachments = target_email.get("attachments", []) or []
    has_attachment = len(attachments) > 0

    # Also check if there's an attachment field as a string
    if not has_attachment:
        att_str = target_email.get("attachment", "")
        if att_str:
            has_attachment = True

    failures = []
    found_details = []

    # (1) Check salutation: addresses 'Avery Solis' or 'Dr. Avery Solis'
    # Check both body and attachment content. Be loose: check case-insensitively too.
    salutation_ok = False
    if re.search(r'Avery\s+Solis', body, re.IGNORECASE):
        salutation_ok = True

    # If there's an attachment, try to read it from workspace to check content
    attachment_content = ""
    if has_attachment:
        for att in (attachments if isinstance(attachments, list) else [attachments]):
            att_name = att if isinstance(att, str) else (att.get("filename") or att.get("name") or "")
            if att_name:
                # Try to find the file in workspace
                att_path = Path(workspace_path) / att_name
                if att_path.exists():
                    try:
                        if att_name.lower().endswith(".pdf"):
                            import pdfplumber
                            with pdfplumber.open(att_path) as pdf:
                                for page in pdf.pages:
                                    txt = page.extract_text()
                                    if txt:
                                        attachment_content += txt + "\n"
                        elif att_name.lower().endswith(".docx"):
                            import docx
                            doc = docx.Document(att_path)
                            for para in doc.paragraphs:
                                attachment_content += para.text + "\n"
                        else:
                            attachment_content += att_path.read_text(errors='ignore')
                    except Exception:
                        pass
                # Also check subdirectories
                else:
                    for found in Path(workspace_path).rglob(att_name):
                        try:
                            if att_name.lower().endswith(".pdf"):
                                import pdfplumber
                                with pdfplumber.open(found) as pdf:
                                    for page in pdf.pages:
                                        txt = page.extract_text()
                                        if txt:
                                            attachment_content += txt + "\n"
                            elif att_name.lower().endswith(".docx"):
                                import docx
                                doc = docx.Document(found)
                                for para in doc.paragraphs:
                                    attachment_content += para.text + "\n"
                            else:
                                attachment_content += found.read_text(errors='ignore')
                        except Exception:
                            pass
                        break

    # Check salutation in attachment content too
    if not salutation_ok and attachment_content:
        if re.search(r'Avery\s+Solis', attachment_content, re.IGNORECASE):
            salutation_ok = True

    if not salutation_ok:
        failures.append("Missing addressee 'Avery Solis' or 'Dr. Avery Solis' in email body or attachment")
    else:
        found_details.append("Addressed Avery Solis")

    # (2) Check required boilerplate key phrases in body OR attachment
    # The rubric says: body contains all required boilerplate OR attaches the letter as a file
    combined_text = body + "\n" + attachment_content

    required_phrases = {
        "In order to complete our review": r"[Ii]n\s+order\s+to\s+complete\s+our\s+review",
        "within 15 calendar days": r"within\s+15\s+calendar\s+days",
        "portal.mojavecrest.com": r"portal\.mojavecrest\.com",
        "Ari Costa": r"Ari\s+Costa",
        "Appeals & Grievances Coordinator": r"Appeals\s*[&and]+\s*Grievances\s*Coordinator",
        "Mojave Crest Assurance Company": r"Mojave\s+Crest\s+Assurance\s+Company",
        "Phone: (702) 555-0148": r"\(?702\)?[\s\-\.]*555[\s\-\.]*0148"
    }

    # If there's an attachment, the rubric allows that as an alternative to having boilerplate in body
    # So we check: either all phrases are in body, OR there is an attachment
    boilerplate_in_body = True
    boilerplate_in_combined = True
    missing_body = []
    missing_combined = []
    for label, pattern in required_phrases.items():
        if not re.search(pattern, body):
            boilerplate_in_body = False
            missing_body.append(label)
        if not re.search(pattern, combined_text):
            boilerplate_in_combined = False
            missing_combined.append(label)
        else:
            found_details.append(f"Found '{label}'")

    # The rubric: body contains all boilerplate OR attaches the letter as a file
    if boilerplate_in_body:
        found_details.append("All boilerplate phrases found in email body")
    elif has_attachment and boilerplate_in_combined:
        found_details.append("Boilerplate content found in attachment")
    elif has_attachment:
        # Has attachment - rubric says "OR attaches the letter as a file" - be generous
        # The attachment itself IS the letter, so having an attachment satisfies this
        found_details.append(f"Letter attached as file (attachment present). Some phrases may be in attachment but couldn't fully verify: missing {missing_combined}")
    else:
        failures.append(f"Missing required boilerplate phrases in body and no attachment found. Missing: {missing_body}")

    if failures:
        return {"pass": False, "score": 0.0, "feedback": "; ".join(failures)}

    return {"pass": True, "score": 1.0, "feedback": "Email correctly sent to asolis@griffinmedical.org with proper content. " + "; ".join(found_details)}

