from pathlib import Path
import re

def verify(workspace_path, external_services_path=None):
    try:
        import pdfplumber
    except ImportError:
        return {"pass": False, "score": 0.0, "feedback": "pdfplumber not available"}

    matches = list(Path(workspace_path).rglob("20260512_KPX658320914_Correspondence.pdf"))
    if not matches:
        # Also try looser glob patterns
        matches = list(Path(workspace_path).rglob("*KPX658320914*Correspondence*.pdf"))
    if not matches:
        matches = list(Path(workspace_path).rglob("*Correspondence*.pdf"))
    if not matches:
        return {"pass": False, "score": 0.0, "feedback": "File '20260512_KPX658320914_Correspondence.pdf' (or similar) not found anywhere in workspace."}

    pdf_path = matches[0]
    try:
        with pdfplumber.open(str(pdf_path)) as pdf:
            text = ""
            for page in pdf.pages:
                text += (page.extract_text() or "") + "\n"
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Error reading PDF '{pdf_path.name}': {e}"}

    if not text.strip():
        return {"pass": False, "score": 0.0, "feedback": f"PDF '{pdf_path.name}' appears to have no extractable text."}

    failures = []
    found_items = []

    # Normalize whitespace for easier matching
    norm_text = re.sub(r'\s+', ' ', text)

    # Check date (accept various formats: 5/12/2026, 05/12/2026, May 12, 2026, 2026-05-12)
    date_patterns = [r"5/12/2026", r"05/12/2026", r"May\s*12,?\s*2026", r"2026-05-12", r"12\s+May\s+2026"]
    date_found = any(re.search(p, text, re.IGNORECASE) for p in date_patterns)
    if not date_found:
        # Also check normalized text
        date_found = any(re.search(p, norm_text, re.IGNORECASE) for p in date_patterns)
    if date_found:
        found_items.append("date 5/12/2026")
    else:
        failures.append("Date 5/12/2026 (or equivalent) not found in document")

    # Check addressee Jules Arden
    if "Jules Arden" in text or "Jules Arden" in norm_text or re.search(r'Jules\s+Arden', text, re.IGNORECASE):
        found_items.append("addressee 'Jules Arden'")
    else:
        failures.append("Addressee 'Jules Arden' not found")

    # Check address components
    addr_issues = []
    if re.search(r'2675\s+Westwind\s+Terrace', text, re.IGNORECASE) or "2675 Westwind Terrace" in norm_text:
        found_items.append("'2675 Westwind Terrace'")
    else:
        addr_issues.append("'2675 Westwind Terrace' not found")

    if re.search(r'Las\s+Vegas', text, re.IGNORECASE):
        found_items.append("'Las Vegas'")
    else:
        addr_issues.append("City 'Las Vegas' not found")

    if re.search(r'NV', text):
        found_items.append("'NV'")
    # NV not strictly required by rubric as separate check, but part of address

    if "89146" in text:
        found_items.append("ZIP '89146'")
    else:
        addr_issues.append("ZIP '89146' not found")

    if addr_issues:
        failures.append("Address issues: " + "; ".join(addr_issues))

    # Check salutation addressing Jules Arden
    salutation_patterns = [
        r'Dear\s+Jules\s+Arden',
        r'Dear\s+Mr\.?\s+Arden',
        r'Dear\s+Ms\.?\s+Arden',
        r'Dear\s+Mrs\.?\s+Arden',
        r'Dear\s+Dr\.?\s+Arden',
        r'Dear\s+Mx\.?\s+Arden',
        r'Dear\s+Jules',
    ]
    salutation_ok = any(re.search(p, text, re.IGNORECASE) for p in salutation_patterns)
    if not salutation_ok:
        salutation_ok = any(re.search(p, norm_text, re.IGNORECASE) for p in salutation_patterns)
    if salutation_ok:
        found_items.append("salutation addressing Jules Arden")
    else:
        failures.append("Salutation addressing 'Jules Arden' not found (expected 'Dear Jules Arden' or similar)")

    # Check required boilerplate phrases per rubric
    boilerplate_checks = [
        ("In order to complete our review", r'[Ii]n\s+order\s+to\s+complete\s+our\s+review'),
        ("within 15 calendar days", r'within\s+15\s+calendar\s+days'),
        ("portal.mojavecrest.com", r'portal\.?\s*mojavecrest\.?\s*com'),
        ("Ari Costa", r'Ari\s+Costa'),
        ("Appeals & Grievances Coordinator", r'Appeals\s*[&and]+\s*Grievances\s+Coordinator'),
        ("Mojave Crest Assurance Company", r'Mojave\s+Crest\s+Assurance\s+Company'),
        ("(702) 555-0148", r'\(?702\)?[\s.-]*555[\s.-]*0148'),
    ]

    missing_phrases = []
    for label, pattern in boilerplate_checks:
        if re.search(pattern, text, re.IGNORECASE) or re.search(pattern, norm_text, re.IGNORECASE):
            found_items.append(f"boilerplate '{label}'")
        else:
            # Also try simple substring match
            if label.lower() in text.lower() or label.lower() in norm_text.lower():
                found_items.append(f"boilerplate '{label}'")
            else:
                missing_phrases.append(label)

    if missing_phrases:
        failures.append(f"Missing boilerplate phrases: {missing_phrases}")

    # Calculate partial score
    total_checks = 7 + len(boilerplate_checks)  # date, addressee, 3 address parts, salutation, + boilerplate
    passed_checks = total_checks - len(failures)
    score = max(0.0, passed_checks / total_checks)

    if failures:
        return {
            "pass": False,
            "score": score,
            "feedback": f"Found in '{pdf_path.name}': {', '.join(found_items)}. FAILURES: {'; '.join(failures)}"
        }

    return {
        "pass": True,
        "score": 1.0,
        "feedback": f"PDF '{pdf_path.name}' verified successfully. Found: {', '.join(found_items)}."
    }

